/* ============ المتغيرات ============ */
:root {
  --bg: #0f172a;
  --bg-2: #1e293b;
  --bg-3: #334155;
  --text: #e2e8f0;
  --text-2: #94a3b8;
  --primary: #6366f1;
  --primary-2: #818cf8;
  --success: #10b981;
  --danger: #ef4444;
  --warning: #f59e0b;
  --border: #334155;
  --code-bg: #1e1b4b;
  --shadow: 0 10px 30px rgba(0,0,0,.3);
  --radius: 16px;
}
[data-theme="light"] {
  --bg: #f8fafc;
  --bg-2: #ffffff;
  --bg-3: #f1f5f9;
  --text: #0f172a;
  --text-2: #475569;
  --border: #e2e8f0;
  --code-bg: #1e293b;
  --shadow: 0 10px 30px rgba(0,0,0,.08);
}

/* ============ عام ============ */
* { box-sizing: border-box; margin: 0; padding: 0; }
html, body { min-height: 100%; }
body {
  font-family: 'Segoe UI', Tahoma, 'Cairo', sans-serif;
  background: var(--bg);
  color: var(--text);
  line-height: 1.7;
  transition: background .3s, color .3s;
}
.container { max-width: 1100px; margin: 0 auto; padding: 24px 20px; }

/* ============ شاشات ============ */
.screen { display: none; min-height: 100vh; animation: fadeIn .4s ease; }
.screen.active { display: block; }
@keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }

/* ============ زر / أزرار ============ */
.btn {
  display: inline-block;
  padding: 12px 24px;
  border: none;
  border-radius: 12px;
  font-size: 16px;
  font-weight: 600;
  cursor: pointer;
  transition: all .2s;
  font-family: inherit;
}
.btn-primary { background: var(--primary); color: white; }
.btn-primary:hover { background: var(--primary-2); transform: translateY(-2px); }
.btn-secondary { background: var(--bg-3); color: var(--text); }
.btn-secondary:hover { background: var(--border); }
.btn-ghost { background: transparent; color: var(--text-2); }
.btn-ghost:hover { color: var(--text); }
.btn:disabled { opacity: .4; cursor: not-allowed; transform: none !important; }
.btn-icon {
  background: var(--bg-2);
  border: 1px solid var(--border);
  color: var(--text);
  padding: 8px 14px;
  border-radius: 10px;
  cursor: pointer;
  font-family: inherit;
  font-size: 14px;
}

/* ============ الصفحة الرئيسية ============ */
.hero {
  text-align: center;
  padding: 60px 0 40px;
}
.logo { font-size: 80px; margin-bottom: 16px; animation: bounce 2s infinite; }
@keyframes bounce { 0%,100% { transform: translateY(0); } 50% { transform: translateY(-10px); } }
.hero h1 { font-size: 48px; margin-bottom: 10px; background: linear-gradient(135deg, var(--primary), var(--primary-2)); -webkit-background-clip: text; background-clip: text; -webkit-text-fill-color: transparent; }
.tagline { color: var(--text-2); font-size: 18px; margin-bottom: 40px; }
.progress-overview {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 16px;
  margin: 40px 0;
}
.stat-card {
  background: var(--bg-2);
  border: 1px solid var(--border);
  padding: 24px;
  border-radius: var(--radius);
}
.stat-num { font-size: 36px; font-weight: bold; color: var(--primary-2); }
.stat-label { color: var(--text-2); font-size: 14px; margin-top: 4px; }

/* ============ شريط علوي ============ */
.top-bar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 16px 0;
  margin-bottom: 24px;
  border-bottom: 1px solid var(--border);
}
.top-bar h2 { font-size: 22px; }

/* ============ شبكة الدروس ============ */
.lessons-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
  gap: 20px;
}
.lesson-card {
  background: var(--bg-2);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 24px;
  cursor: pointer;
  transition: all .3s;
  position: relative;
  overflow: hidden;
}
.lesson-card:hover { transform: translateY(-4px); border-color: var(--primary); box-shadow: var(--shadow); }
.lesson-card .icon { font-size: 42px; margin-bottom: 12px; }
.lesson-card h3 { margin-bottom: 8px; font-size: 20px; }
.lesson-card p { color: var(--text-2); font-size: 14px; }
.lesson-card .badge {
  position: absolute;
  top: 12px;
  left: 12px;
  background: var(--success);
  color: white;
  padding: 4px 10px;
  border-radius: 20px;
  font-size: 12px;
  font-weight: bold;
}
.lesson-card .difficulty {
  margin-top: 12px;
  font-size: 13px;
  color: var(--text-2);
}

/* ============ محتوى الدرس ============ */
.lesson-content {
  background: var(--bg-2);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 32px;
  margin-bottom: 24px;
}
.lesson-content h1 {
  font-size: 32px;
  margin-bottom: 16px;
  color: var(--primary-2);
}
.lesson-content h2 {
  font-size: 24px;
  margin: 28px 0 12px;
  color: var(--primary);
  border-right: 4px solid var(--primary);
  padding-right: 12px;
}
.lesson-content h3 { font-size: 18px; margin: 16px 0 8px; }
.lesson-content p { margin-bottom: 12px; color: var(--text); }
.lesson-content ul, .lesson-content ol { padding-right: 24px; margin-bottom: 16px; }
.lesson-content li { margin-bottom: 8px; }
.lesson-content code {
  background: var(--code-bg);
  color: #c7d2fe;
  padding: 2px 8px;
  border-radius: 6px;
  font-family: 'Courier New', monospace;
  font-size: 14px;
}
.lesson-content pre {
  background: var(--code-bg);
  color: #e0e7ff;
  padding: 16px;
  border-radius: 10px;
  overflow-x: auto;
  margin: 12px 0 20px;
  direction: ltr;
  text-align: left;
  border: 1px solid rgba(99, 102, 241, .3);
}
.lesson-content pre code { background: none; padding: 0; }
.lesson-content .tip {
  background: rgba(245, 158, 11, .1);
  border-right: 4px solid var(--warning);
  padding: 14px;
  border-radius: 8px;
  margin: 16px 0;
  color: var(--text);
}
.lesson-content .tip strong { color: var(--warning); }
.lesson-actions {
  display: flex;
  gap: 12px;
  justify-content: center;
  flex-wrap: wrap;
}

/* ============ الامتحان ============ */
.exam-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 24px;
  background: var(--bg-2);
  padding: 16px 20px;
  border-radius: var(--radius);
  border: 1px solid var(--border);
}
.exam-progress { flex: 1; }
.progress-bar {
  margin-top: 8px;
  height: 8px;
  background: var(--bg-3);
  border-radius: 4px;
  overflow: hidden;
}
.progress-fill {
  height: 100%;
  background: linear-gradient(90deg, var(--primary), var(--primary-2));
  width: 0%;
  transition: width .3s;
}
.timer {
  font-size: 18px;
  font-weight: bold;
  color: var(--warning);
  margin-right: 16px;
}

.question-card {
  background: var(--bg-2);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 32px;
  margin-bottom: 24px;
  min-height: 300px;
}
.question-text {
  font-size: 20px;
  font-weight: 600;
  margin-bottom: 24px;
  line-height: 1.6;
}
.options { display: flex; flex-direction: column; gap: 12px; }
.option {
  background: var(--bg-3);
  border: 2px solid var(--border);
  border-radius: 12px;
  padding: 16px 20px;
  cursor: pointer;
  transition: all .2s;
  display: flex;
  align-items: center;
  gap: 12px;
}
.option:hover { border-color: var(--primary); }
.option.selected { border-color: var(--primary); background: rgba(99, 102, 241, .15); }
.option.correct { border-color: var(--success); background: rgba(16, 185, 129, .15); }
.option.wrong { border-color: var(--danger); background: rgba(239, 68, 68, .15); }
.option .opt-letter {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  background: var(--bg);
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: bold;
  border: 1px solid var(--border);
}
.option.correct .opt-letter { background: var(--success); color: white; border-color: var(--success); }
.option.wrong .opt-letter { background: var(--danger); color: white; border-color: var(--danger); }

.exam-actions {
  display: flex;
  justify-content: space-between;
  gap: 12px;
}

/* ============ النتيجة ============ */
.result-card {
  background: var(--bg-2);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 48px 32px;
  text-align: center;
  margin-top: 40px;
  box-shadow: var(--shadow);
}
.result-icon { font-size: 80px; margin-bottom: 16px; }
.result-card h2 { font-size: 32px; margin-bottom: 24px; }

.score-circle {
  position: relative;
  width: 180px;
  height: 180px;
  margin: 24px auto;
}
.score-circle svg { transform: rotate(-90deg); width: 100%; height: 100%; }
.score-bg { fill: none; stroke: var(--bg-3); stroke-width: 8; }
.score-fill {
  fill: none;
  stroke: var(--success);
  stroke-width: 8;
  stroke-linecap: round;
  stroke-dasharray: 282.6;
  stroke-dashoffset: 282.6;
  transition: stroke-dashoffset 1.5s ease, stroke .3s;
}
.score-text {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  font-size: 42px;
  font-weight: bold;
}
.score-text small { font-size: 22px; color: var(--text-2); }

#resultMsg { color: var(--text-2); font-size: 16px; margin: 16px 0 24px; }

.result-details {
  background: var(--bg-3);
  padding: 20px;
  border-radius: 12px;
  margin: 24px 0;
  text-align: right;
}
.result-details div {
  display: flex;
  justify-content: space-between;
  padding: 8px 0;
  border-bottom: 1px solid var(--border);
}
.result-details div:last-child { border-bottom: none; }

.result-actions {
  display: flex;
  gap: 12px;
  justify-content: center;
  flex-wrap: wrap;
  margin-top: 24px;
}

/* ============ المراجعة ============ */
.review-item {
  background: var(--bg-2);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 24px;
  margin-bottom: 16px;
  border-right: 4px solid var(--border);
}
.review-item.correct-w { border-right-color: var(--success); }
.review-item.wrong-w { border-right-color: var(--danger); }
.review-item h3 { margin-bottom: 12px; font-size: 18px; }
.review-item .your-answer {
  margin: 8px 0;
  padding: 10px;
  border-radius: 8px;
  background: var(--bg-3);
}
.review-item .your-answer.wrong-a { background: rgba(239, 68, 68, .15); }
.review-item .your-answer.right-a { background: rgba(16, 185, 129, .15); }
.review-item .explanation {
  margin-top: 12px;
  padding: 12px;
  background: rgba(99, 102, 241, .1);
  border-radius: 8px;
  font-size: 14px;
  color: var(--text-2);
}

/* ============ Responsive ============ */
@media (max-width: 768px) {
  .hero h1 { font-size: 32px; }
  .progress-overview { grid-template-columns: 1fr; }
  .lesson-content { padding: 20px; }
  .lesson-content h1 { font-size: 24px; }
  .exam-header { flex-direction: column; gap: 12px; }
  .timer { margin-right: 0; }
  .question-card { padding: 20px; }
  .score-circle { width: 140px; height: 140px; }
}

// ============ الحالة ============
const state = {
  currentLesson: null,
  exam: { questions: [], answers: [], currentIdx: 0, timer: 0, intervalId: null },
  progress: JSON.parse(localStorage.getItem('study-progress') || '{}')
};

function saveProgress() {
  localStorage.setItem('study-progress', JSON.stringify(state.progress));
}

// ============ التنقل ============
function goTo(screenId) {
  if (state.exam.intervalId && screenId !== 'examScreen') {
    clearInterval(state.exam.intervalId);
    state.exam.intervalId = null;
  }
  document.querySelectorAll('.screen').forEach(s => s.classList.remove('active'));
  document.getElementById(screenId).classList.add('active');
  window.scrollTo({ top: 0, behavior: 'smooth' });
}

document.querySelectorAll('[data-go]').forEach(el => {
  el.addEventListener('click', () => goTo(el.dataset.go));
});

// ============ الثيم ============
document.getElementById('themeToggle').addEventListener('click', () => {
  const html = document.documentElement;
  const next = html.dataset.theme === 'dark' ? 'light' : 'dark';
  html.dataset.theme = next;
  localStorage.setItem('theme', next);
});
if (localStorage.getItem('theme')) {
  document.documentElement.dataset.theme = localStorage.getItem('theme');
}

// ============ تحديث الإحصائيات ============
function updateStats() {
  const completed = Object.keys(state.progress).length;
  let totalScore = 0, examCount = 0;
  Object.values(state.progress).forEach(p => {
    if (p.bestScore !== undefined) {
      totalScore += p.bestScore;
      examCount++;
    }
  });
  const avg = examCount > 0 ? Math.round(totalScore / examCount) : 0;
  document.getElementById('completedCount').textContent = completed;
  document.getElementById('avgScore').textContent = avg + '%';
  document.getElementById('totalExams').textContent = examCount;
}

// ============ عرض الدروس ============
function renderLessons() {
  const grid = document.getElementById('lessonsGrid');
  grid.innerHTML = LESSONS.map(l => {
    const done = state.progress[l.id];
    return `
      <div class="lesson-card" data-id="${l.id}">
        ${done ? '<div class="badge">✓ ' + (done.bestScore || 0) + '%</div>' : ''}
        <div class="icon">${l.icon}</div>
        <h3>${l.title}</h3>
        <p>${l.description}</p>
        <div class="difficulty">📊 ${l.difficulty}</div>
      </div>`;
  }).join('');
  grid.querySelectorAll('.lesson-card').forEach(card => {
    card.addEventListener('click', () => openLesson(card.dataset.id));
  });
}

function openLesson(id) {
  const lesson = LESSONS.find(l => l.id === id);
  state.currentLesson = lesson;
  document.getElementById('lessonTitle').textContent = lesson.title;
  document.getElementById('lessonContent').innerHTML = lesson.content;
  goTo('lessonScreen');
}

// ============ بدء الامتحان ============
function startExam() {
  const lesson = state.currentLesson;
  const questions = [...lesson.exam].sort(() => Math.random() - .5).slice(0, Math.min(6, lesson.exam.length));
  state.exam = {
    questions,
    answers: new Array(questions.length).fill(null),
    currentIdx: 0,
    timer: 0,
    intervalId: setInterval(() => {
      state.exam.timer++;
      const m = String(Math.floor(state.exam.timer / 60)).padStart(2, '0');
      const s = String(state.exam.timer % 60).padStart(2, '0');
      document.getElementById('timer').textContent = `⏱️ ${m}:${s}`;
    }, 1000)
  };
  goTo('examScreen');
  renderQuestion();
}

function renderQuestion() {
  const { questions, currentIdx, answers } = state.exam;
  const q = questions[currentIdx];
  const total = questions.length;

  document.getElementById('questionCounter').textContent =
    `سؤال ${currentIdx + 1} من ${total}`;
  document.getElementById('progressFill').style.width =
    `${((currentIdx + 1) / total) * 100}%`;
  document.getElementById('btnPrev').disabled = currentIdx === 0;
  document.getElementById('btnNext').textContent =
    currentIdx === total - 1 ? 'إنهاء الامتحان ✓' : 'التالي ►';

  const card = document.getElementById('questionCard');
  let html = `<div class="question-text">${q.q}</div><div class="options">`;

  if (q.type === 'mcq') {
    q.options.forEach((opt, i) => {
      const arabicLetters = ['أ', 'ب', 'ج', 'د', 'هـ'];
      const isSel = answers[currentIdx] === i;
      if (answers[currentIdx] !== null && i === q.answer) {
        html += `<div class="option correct">
          <span class="opt-letter">✓</span><span>${opt}</span>
        </div>`;
      } else if (isSel && i !== q.answer) {
        html += `<div class="option wrong">
          <span class="opt-letter">✗</span><span>${opt}</span>
        </div>`;
      } else {
        html += `<div class="option" data-opt="${i}">
          <span class="opt-letter">${arabicLetters[i]}</span><span>${opt}</span>
        </div>`;
      }
    });
  } else { // true/false
    const choices = [['صح ✓', true], ['خطأ ✗', false]];
    choices.forEach(([label, val]) => {
      const isSel = answers[currentIdx] === val;
      const isCorrect = val === q.answer;
      if (answers[currentIdx] !== null && isCorrect) {
        html += `<div class="option correct">
          <span class="opt-letter">✓</span><span>${label}</span>
        </div>`;
      } else if (isSel && !isCorrect) {
        html += `<div class="option wrong">
          <span class="opt-letter">✗</span><span>${label}</span>
        </div>`;
      } else {
        html += `<div class="option" data-tf="${val}">
          <span class="opt-letter">${label.charAt(0)}</span><span>${label}</span>
        </div>`;
      }
    });
  }
  html += '</div>';
  card.innerHTML = html;

  if (answers[currentIdx] === null) {
    card.querySelectorAll('[data-opt]').forEach(el => {
      el.addEventListener('click', () => {
        state.exam.answers[currentIdx] = parseInt(el.dataset.opt);
        renderQuestion();
      });
    });
    card.querySelectorAll('[data-tf]').forEach(el => {
      el.addEventListener('click', () => {
        const v = el.dataset.tf === 'true';
        state.exam.answers[currentIdx] = v;
        renderQuestion();
      });
    });
  }
}

// ============ أزرار الامتحان ============
document.getElementById('btnPrev').addEventListener('click', () => {
  if (state.exam.currentIdx > 0) {
    state.exam.currentIdx--;
    renderQuestion();
  }
});
document.getElementById('btnNext').addEventListener('click', () => {
  const { currentIdx, answers, questions } = state.exam;
  if (answers[currentIdx] === null) {
    alert('الرجاء اختيار إجابة أولاً');
    return;
  }
  if (currentIdx < questions.length - 1) {
    state.exam.currentIdx++;
    renderQuestion();
  } else {
    finishExam();
  }
});

// ============ إنهاء الامتحان ============
function finishExam() {
  clearInterval(state.exam.intervalId);
  const { questions, answers } = state.exam;
  let correct = 0;
  questions.forEach((q, i) => {
    if (answers[i] === q.answer) correct++;
  });
  const pct = Math.round((correct / questions.length) * 100);

  // حفظ التقدم
  const lid = state.currentLesson.id;
  if (!state.progress[lid]) state.progress[lid] = {};
  state.progress[lid].bestScore = Math.max(pct, state.progress[lid].bestScore || 0);
  state.progress[lid].lastScore = pct;
  state.progress[lid].completed = true;
  state.progress[lid].date = new Date().toLocaleString('ar');
  saveProgress();

  // عرض النتيجة
  const icon = pct >= 80 ? '🎉' : pct >= 50 ? '👍' : '📚';
  const title = pct >= 80 ? 'ممتاز!' : pct >= 50 ? 'جيد، استمر!' : 'تحتاج مراجعة';
  const msg = pct >= 80 ? 'أداء رائع! أنت فاهم المادة.' :
              pct >= 50 ? 'مستوى جيد لكن في مجال للتحسن.' :
              'أعد قراءة الدرس وحاول مرة أخرى.';
  document.getElementById('resultIcon').textContent = icon;
  document.getElementById('resultTitle').textContent = title;
  document.getElementById('resultMsg').textContent = msg;
  document.getElementById('scoreNum').textContent = pct;
  document.getElementById('resultDetails').innerHTML = `
    <div><span>الإجابات الصحيحة</span><strong>${correct} / ${questions.length}</strong></div>
    <div><span>النسبة</span><strong>${pct}%</strong></div>
    <div><span>الوقت</span><strong>${Math.floor(state.exam.timer / 60)}:${String(state.exam.timer % 60).padStart(2, '0')}</strong></div>
  `;
  setTimeout(() => {
    const dashOffset = 282.6 - (pct / 100) * 282.6;
    const circle = document.getElementById('scoreCircle');
    circle.style.strokeDashoffset = dashOffset;
    circle.style.stroke = pct >= 80 ? '#10b981' : pct >= 50 ? '#f59e0b' : '#ef4444';
  }, 100);

  goTo('resultScreen');
  updateStats();
}

// ============ المراجعة ============
function showReview() {
  const { questions, answers } = state.exam;
  const html = questions.map((q, i) => {
    const isCorrect = answers[i] === q.answer;
    let userAnswer;
    if (q.type === 'mcq') {
      userAnswer = answers[i] !== null ? q.options[answers[i]] : 'لم يُجب';
    } else {
      userAnswer = answers[i] !== null ? (answers[i] ? 'صح' : 'خطأ') : 'لم يُجب';
    }
    let correctAnswer;
    if (q.type === 'mcq') {
      correctAnswer = q.options[q.answer];
    } else {
      correctAnswer = q.answer ? 'صح' : 'خطأ';
    }
    return `
      <div class="review-item ${isCorrect ? 'correct-w' : 'wrong-w'}">
        <h3>${i + 1}. ${q.q}</h3>
        <div class="your-answer ${isCorrect ? 'right-a' : 'wrong-a'}">
          <strong>إجابتك:</strong> ${userAnswer} ${isCorrect ? '✅' : '❌'}
        </div>
        ${!isCorrect ? `<div class="your-answer right-a">
          <strong>الإجابة الصحيحة:</strong> ${correctAnswer}
        </div>` : ''}
        <div class="explanation">💡 ${q.exp}</div>
      </div>`;
  }).join('');
  document.getElementById('reviewContent').innerHTML = html;
  goTo('reviewScreen');
}

document.getElementById('btnReview').addEventListener('click', showReview);
document.getElementById('backToResult').addEventListener('click', () => goTo('resultScreen'));

// ============ إعادة الامتحان ============
document.getElementById('btnRetake').addEventListener('click', startExam);

// ============ زر البداية ============
document.getElementById('startBtn').addEventListener('click', () => {
  renderLessons();
  goTo('lessonsScreen');
});
document.getElementById('btnReRead').addEventListener('click', () => {
  const c = document.getElementById('lessonContent');
  c.scrollTo({ top: 0 });
  window.scrollTo({ top: 0, behavior: 'smooth' });
});
document.getElementById('btnStartExam').addEventListener('click', startExam);

// ============ بداية التطبيق ============
updateStats();

