arguments.content:
:root{
  --bg:#0a0a1a;--bg-2:#12122a;--bg-3:#1a1a35;
  --surface:rgba(255,255,255,.04);
  --surface-2:rgba(255,255,255,.07);
  --border:rgba(255,255,255,.08);
  --border-2:rgba(255,255,255,.14);
  --text:#f1f1fa;--text-2:#9b9bb8;--text-3:#5d5d7a;
  --p:#7c3aed;--p-2:#a78bfa;--c:#06b6d4;--c-2:#22d3ee;
  --suc:#10b981;--suc-2:#34d399;
  --dan:#ef4444;--dan-2:#f87171;
  --warn:#f59e0b;
  --grad-p:linear-gradient(135deg,#7c3aed,#06b6d4);
  --grad-w:linear-gradient(135deg,#f59e0b,#ef4444);
  --grad-s:linear-gradient(135deg,#10b981,#06b6d4);
  --shadow:0 20px 60px rgba(0,0,0,.5);
  --glow:0 0 40px rgba(124,58,237,.4);
  --r:20px;--r-sm:12px;
  --ease:cubic-bezier(.4,0,.2,1);
}
[data-theme="light"]{
  --bg:#f8f7fc;--bg-2:#ffffff;--bg-3:#f1eef9;
  --surface:rgba(255,255,255,.7);--surface-2:rgba(255,255,255,.9);
  --border:rgba(124,58,237,.1);--border-2:rgba(124,58,237,.2);
  --text:#1a1a2e;--text-2:#5d5d7a;--text-3:#9b9bb8;
  --shadow:0 20px 60px rgba(124,58,237,.15);
}

*{box-sizing:border-box;margin:0;padding:0;}
html,body{min-height:100%;}
body{
  font-family:'Cairo','Segoe UI','Tajawal',sans-serif;
  background:var(--bg);color:var(--text);line-height:1.7;
  overflow-x:hidden;
  background-image:radial-gradient(at 20% 0%,rgba(124,58,237,.15) 0%,transparent 50%),
                   radial-gradient(at 80% 100%,rgba(6,182,212,.1) 0%,transparent 50%);
}
.container{max-width:1200px;margin:0 auto;padding:24px 20px;}

/* ============ Aurora Background ============ */
.aurora{position:fixed;inset:0;z-index:-1;overflow:hidden;pointer-events:none;}
.orb{position:absolute;border-radius:50%;filter:blur(80px);opacity:.4;mix-blend-mode:screen;}
.o1{width:500px;height:500px;background:#7c3aed;top:-100px;right:-100px;animation:float1 20s infinite;}
.o2{width:400px;height:400px;background:#06b6d4;bottom:-50px;left:-100px;animation:float2 25s infinite;}
.o3{width:300px;height:300px;background:#ec4899;top:50%;left:50%;animation:float3 18s infinite;}
@keyframes float1{0%,100%{transform:translate(0,0)}50%{transform:translate(-100px,100px)}}
@keyframes float2{0%,100%{transform:translate(0,0)}50%{transform:translate(80px,-80px)}}
@keyframes float3{0%,100%{transform:translate(-50%,-50%)}50%{transform:translate(-30%,-70%)}}

/* ============ Navbar ============ */
.navbar{position:sticky;top:0;z-index:100;backdrop-filter:blur(20px);background:rgba(10,10,26,.7);border-bottom:1px solid var(--border);}
.nav-inner{max-width:1200px;margin:0 auto;padding:14px 24px;display:flex;justify-content:space-between;align-items:center;}
.brand{display:flex;align-items:center;gap:10px;font-weight:bold;font-size:18px;cursor:pointer;}
.brand-icon{width:36px;height:36px;border-radius:10px;background:var(--grad-p);display:grid;place-items:center;font-size:18px;color:white;box-shadow:var(--glow);}
.nav-stats{display:flex;gap:10px;align-items:center;}
.nav-pill{display:flex;align-items:center;gap:6px;padding:6px 12px;background:var(--surface);border:1px solid var(--border-2);border-radius:100px;font-size:14px;}
.nav-pill small{font-size:11px;color:var(--text-2);}
.theme-btn{width:36px;height:36px;border:none;background:var(--surface);border:1px solid var(--border-2);border-radius:50%;cursor:pointer;font-size:16px;color:var(--text);transition:.2s;}
.theme-btn:hover{transform:rotate(30deg) scale(1.1);}

/* ============ Screens ============ */
.screen{display:none;min-height:calc(100vh - 70px);animation:fadeUp .5s var(--ease);}
.screen.active{display:block;}
@keyframes fadeUp{from{opacity:0;transform:translateY(20px)}to{opacity:1;transform:translateY(0)}}

/* ============ Hero ============ */
.hero-wrap{padding:80px 0 40px;text-align:center;}
.hero-badge{display:inline-block;padding:6px 16px;background:var(--surface);border:1px solid var(--border-2);border-radius:100px;font-size:13px;margin-bottom:24px;backdrop-filter:blur(10px);}
.hero-title{font-size:clamp(36px,6vw,72px);font-weight:800;line-height:1.1;margin-bottom:20px;letter-spacing:-1px;}
.gradient-text{background:var(--grad-p);-webkit-background-clip:text;background-clip:text;-webkit-text-fill-color:transparent;}
.hero-sub{color:var(--text-2);font-size:18px;margin-bottom:40px;max-width:600px;margin-left:auto;margin-right:auto;}
.hero-actions{display:flex;gap:14px;justify-content:center;flex-wrap:wrap;margin-bottom:60px;}

/* ============ Buttons ============ */
.btn-modern{padding:14px 28px;border:none;border-radius:14px;font-size:15px;font-weight:600;cursor:pointer;display:inline-flex;align-items:center;gap:10px;font-family:inherit;transition:all .25s var(--ease);}
.btn-modern.primary{background:var(--grad-p);color:white;box-shadow:0 10px 30px rgba(124,58,237,.4);}
.btn-modern.primary:hover{transform:translateY(-3px);box-shadow:0 15px 40px rgba(124,58,237,.6);}
.btn-modern.gradient{background:var(--grad-s);color:white;}
.btn-modern.ghost{background:var(--surface);color:var(--text);border:1px solid var(--border-2);backdrop-filter:blur(10px);}
.btn-modern.ghost:hover{background:var(--surface-2);transform:translateY(-2px);}
.btn-modern:disabled{opacity:.4;cursor:not-allowed;transform:none!important;}

/* ============ Glass Cards Grid ============ */
.glass-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:16px;margin-bottom:60px;}
.glass-card,.mod-card{
  background:var(--surface);backdrop-filter:blur(20px);
  border:1px solid var(--border-2);border-radius:var(--r);
  padding:24px;transition:all .3s var(--ease);
}
.glass-card{text-align:center;}
.glass-icon{font-size:36px;margin-bottom:8px;}
.glass-num{font-size:42px;font-weight:800;background:var(--grad-p);-webkit-background-clip:text;background-clip:text;-webkit-text-fill-color:transparent;}
.glass-label{font-size:13px;color:var(--text-2);margin-top:4px;}

/* ============ Achievements ============ */
.achievements-section{margin-top:60px;}
.achievements-section h3{font-size:24px;margin-bottom:20px;text-align:center;}
.ach-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(140px,1fr));gap:12px;}
.ach{background:var(--surface);border:1px solid var(--border);padding:16px;border-radius:var(--r-sm);text-align:center;transition:.3s;}
.ach.unlocked{background:linear-gradient(135deg,rgba(124,58,237,.15),rgba(6,182,212,.15));border-color:var(--p-2);transform:scale(1.02);box-shadow:var(--glow);}
.ach.locked{opacity:.35;filter:grayscale(.8);}
.ach-icon{font-size:32px;margin-bottom:6px;}
.ach-name{font-size:12px;font-weight:600;}
.ach-desc{font-size:10px;color:var(--text-2);margin-top:2px;}

/* ============ Page Header ============ */
.page-header{display:grid;grid-template-columns:auto 1fr auto;align-items:center;gap:14px;padding:24px 0;}
.page-header h1{font-size:clamp(20px,4vw,32px);font-weight:700;text-align:center;}
.icon-btn{width:40px;height:40px;border:none;background:var(--surface);border:1px solid var(--border-2);border-radius:12px;cursor:pointer;color:var(--text);font-size:18px;transition:.2s;}
.icon-btn:hover{background:var(--surface-2);transform:scale(1.05);}

/* ============ Filter Chips ============ */
.filter-bar{display:flex;gap:10px;justify-content:center;flex-wrap:wrap;margin-bottom:32px;}
.filter-chip{padding:8px 18px;border:1px solid var(--border-2);background:var(--surface);border-radius:100px;cursor:pointer;font-family:inherit;color:var(--text-2);font-size:14px;transition:.2s;}
.filter-chip.active{background:var(--grad-p);color:white;border-color:transparent;}
.filter-chip:hover:not(.active){transform:translateY(-2px);}

/* ============ Lesson Grid ============ */
.mod-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:20px;}
.mod-card{cursor:pointer;position:relative;overflow:hidden;padding:0;}
.mod-card::before{content:'';position:absolute;inset:0;border-radius:var(--r);padding:1px;background:var(--grad-p);-webkit-mask:linear-gradient(#fff 0 0) content-box,linear-gradient(#fff 0 0);-webkit-mask-composite:xor;mask-composite:exclude;opacity:0;transition:.3s;}
.mod-card:hover::before{opacity:1;}
.mod-card:hover{transform:translateY(-6px);box-shadow:var(--shadow);}
.lesson-tile{padding:28px;position:relative;}

.lesson-icon{width:60px;height:60px;border-radius:16px;display:grid;place-items:center;font-size:32px;margin-bottom:16px;position:relative;}
.lesson-icon::after{content:'';position:absolute;inset:0;border-radius:16px;background:inherit;opacity:.3;filter:blur(15px);z-index:-1;}
.lesson-tile h3{font-size:20px;margin-bottom:8px;font-weight:700;}
.lesson-tile p{color:var(--text-2);font-size:14px;margin-bottom:16px;}
.lesson-tile .diff{display:inline-block;padding:4px 12px;border-radius:100px;font-size:11px;font-weight:600;}
.diff-مبتدئ{background:rgba(16,185,129,.15);color:var(--suc-2);}
.diff-متوسط{background:rgba(245,158,11,.15);color:var(--warn);}
.diff-متقدم{background:rgba(239,68,68,.15);color:var(--dan-2);}
.lesson-tile .badge-top{position:absolute;top:14px;left:14px;background:var(--suc);color:white;padding:3px 10px;border-radius:100px;font-size:11px;font-weight:600;}
.lesson-tile .arrow{position:absolute;bottom:20px;left:20px;font-size:20px;opacity:.4;transition:.3s;}
.mod-card:hover .arrow{opacity:1;transform:translateX(-5px);}

/* ============ Lesson Page ============ */
.lesson-wrap{max-width:900px;}
.lesson-html{padding:32px;}
.lesson-html h1{font-size:32px;margin-bottom:16px;background:var(--grad-p);-webkit-background-clip:text;background-clip:text;-webkit-text-fill-color:transparent;}
.lesson-html h2{font-size:22px;margin:28px 0 14px;color:var(--p-2);padding-right:14px;border-right:3px solid var(--p);}
.lesson-html h3{font-size:18px;margin:18px 0 10px;}
.lesson-html p{margin-bottom:14px;line-height:1.9;}
.lesson-html ul,.lesson-html ol{padding-right:24px;margin-bottom:16px;}
.lesson-html li{margin-bottom:8px;}
.lesson-html code{background:rgba(124,58,237,.15);color:var(--p-2);padding:2px 8px;border-radius:6px;font-size:14px;}
.lesson-html pre{background:rgba(10,10,30,.7);padding:18px;border-radius:12px;overflow-x:auto;margin:14px 0 22px;direction:ltr;text-align:left;border:1px solid var(--border-2);}
.lesson-html pre code{background:none;color:#e0e7ff;padding:0;}
.lesson-html .tip{background:linear-gradient(135deg,rgba(245,158,11,.1),rgba(239,68,68,.05));border-right:4px solid var(--warn);padding:14px;border-radius:10px;margin:16px 0;}
.lesson-html .tip strong{color:var(--warn);}
.lesson-cta{display:flex;gap:12px;justify-content:center;flex-wrap:wrap;margin-top:30px;}

/* ============ Exam ============ */
.exam-wrap{max-width:800px;}
.exam-bar{display:flex;justify-content:space-between;align-items:center;padding:18px 22px;margin-bottom:20px;gap:14px;}
.exam-progress{flex:1;}
.exam-progress span{font-size:14px;color:var(--text-2);}
.prog-track{height:6px;background:rgba(255,255,255,.08);border-radius:3px;overflow:hidden;margin-top:8px;}
.prog-fill{height:100%;background:var(--grad-p);transition:width .3s;border-radius:3px;}
.exam-timer{font-size:20px;font-weight:700;color:var(--warn);font-variant-numeric:tabular-nums;}

.question-card{padding:36px;min-height:340px;}
.q-text{font-size:20px;font-weight:700;margin-bottom:28px;line-height:1.5;}
.q-num{display:inline-block;background:var(--grad-p);color:white;padding:2px 12px;border-radius:100px;font-size:14px;margin-bottom:10px;}
.opts{display:flex;flex-direction:column;gap:10px;}
.opt{
  padding:16px 20px;background:rgba(255,255,255,.03);border:1.5px solid var(--border-2);
  border-radius:14px;cursor:pointer;transition:all .25s var(--ease);
  display:flex;align-items:center;gap:14px;font-size:15px;
}
.opt:hover{border-color:var(--p);background:rgba(124,58,237,.08);transform:translateX(-4px);}
.opt.selected{border-color:var(--p);background:rgba(124,58,237,.15);}
.opt.correct{border-color:var(--suc);background:linear-gradient(135deg,rgba(16,185,129,.2),rgba(16,185,129,.1));animation:correctPulse .5s;}
.opt.wrong{border-color:var(--dan);background:linear-gradient(135deg,rgba(239,68,68,.2),rgba(239,68,68,.1));animation:wrongShake .4s;}
.opt-letter{width:38px;height:38px;border-radius:50%;display:grid;place-items:center;font-weight:700;background:var(--surface);border:1px solid var(--border-2);transition:.25s;}
.opt.correct .opt-letter{background:var(--suc);border-color:var(--suc);color:white;}
.opt.wrong .opt-letter{background:var(--dan);border-color:var(--dan);color:white;}
@keyframes correctPulse{0%,100%{transform:scale(1)}50%{transform:scale(1.02)}}
@keyframes wrongShake{0%,100%{transform:translateX(0)}25%{transform:translateX(-8px)}75%{transform:translateX(8px)}}

.exam-nav{display:flex;justify-content:space-between;gap:12px;margin-top:24px;}

/* ============ Result ============ */
.result-card{padding:48px 32px;text-align:center;position:relative;overflow:hidden;}
.result-emoji{font-size:96px;margin-bottom:16px;animation:popIn .6s cubic-bezier(.34,1.56,.64,1);}
@keyframes popIn{0%{transform:scale(0);opacity:0}100%{transform:scale(1);opacity:1}}
.result-card h1{font-size:42px;margin-bottom:12px;background:var(--grad-p);-webkit-background-clip:text;background-clip:text;-webkit-text-fill-color:transparent;}
.result-card p{color:var(--text-2);margin-bottom:24px;max-width:500px;margin-left:auto;margin-right:auto;}

.ring-wrap{position:relative;width:180px;height:180px;margin:20px auto 32px;}
.ring-svg{transform:rotate(-90deg);width:100%;height:100%;filter:drop-shadow(0 0 20px rgba(124,58,237,.4));}
.ring-bg{fill:none;stroke:rgba(255,255,255,.1);stroke-width:8;}
.ring-fg{fill:none;stroke:url(#ringGrad);stroke-width:8;stroke-linecap:round;stroke-dasharray:326.7;stroke-dashoffset:326.7;transition:stroke-dashoffset 1.5s cubic-bezier(.34,1.56,.64,1);}
.ring-text{position:absolute;inset:0;display:grid;place-items:center;font-size:48px;font-weight:800;}
.ring-text small{font-size:24px;color:var(--text-2);}

.result-stats{display:grid;grid-template-columns:repeat(4,1fr);gap:14px;margin-bottom:30px;}
.result-stats>div{background:rgba(255,255,255,.04);padding:14px;border-radius:12px;border:1px solid var(--border);}
.result-stats strong{display:block;font-size:24px;color:var(--p-2);}
.result-stats span{font-size:11px;color:var(--text-2);}

.achievement-pop{background:linear-gradient(135deg,rgba(245,158,11,.2),rgba(239,68,68,.2));border:1px solid var(--warn);padding:14px 20px;border-radius:14px;margin-bottom:20px;display:inline-flex;align-items:center;gap:10px;animation:slideUp .5s;}
@keyframes slideUp{from{transform:translateY(20px);opacity:0}to{transform:translateY(0);opacity:1}}

.result-actions{display:flex;gap:10px;justify-content:center;flex-wrap:wrap;}

/* ============ Review ============ */
.review-item{background:var(--surface);backdrop-filter:blur(20px);border:1px solid var(--border-2);border-radius:var(--r);padding:24px;margin-bottom:16px;border-right:4px solid var(--border-2);transition:.3s;}
.review-item.r{border-right-color:var(--suc);}
.review-item.w{border-right-color:var(--dan);}
.review-item h3{font-size:17px;margin-bottom:14px;}
.review-item .ya{margin:8px 0;padding:12px;border-radius:10px;background:rgba(255,255,255,.04);font-size:14px;}
.ya.ya-r{background:rgba(16,185,129,.15);color:var(--suc-2);}
.ya.ya-w{background:rgba(239,68,68,.15);color:var(--dan-2);}
.explain{background:rgba(124,58,237,.1);padding:12px;border-radius:10px;font-size:13px;color:var(--text-2);margin-top:10px;border-right:3px solid var(--p);}

/* ============ Toast ============ */
.toast{position:fixed;bottom:30px;left:50%;transform:translateX(-50%) translateY(100px);background:var(--grad-p);color:white;padding:14px 24px;border-radius:14px;font-weight:600;z-index:200;transition:.4s cubic-bezier(.34,1.56,.64,1);box-shadow:0 20px 40px rgba(124,58,237,.4);}
.toast.show{transform:translateX(-50%) translateY(0);}
.toast.warn{background:var(--warn);}
.toast.err{background:var(--dan);}

/* ============ Confetti ============ */
.confetti{position:absolute;inset:0;pointer-events:none;overflow:hidden;}
.confetti i{position:absolute;width:8px;height:14px;top:-20px;animation:fall 3s linear forwards;}
@keyframes fall{to{transform:translateY(120vh) rotate(720deg);opacity:0}}

/* ============ Responsive ============ */
@media(max-width:768px){
  .hero-wrap{padding:40px 0 20px;}
  .result-stats{grid-template-columns:repeat(2,1fr);}
  .question-card{padding:24px;}
  .lesson-html{padding:20px;}
  .exam-bar{flex-direction:column;align-items:stretch;}
  .exam-timer{text-align:center;}
  .nav-pill span:last-child{font-size:13px;}
}

// ============ State ============
const S = {
  currentLesson:null,
  exam:{questions:[],answers:[],idx:0,timer:0,int:null},
  progress:JSON.parse(localStorage.getItem('mp')||'{}'),
  user:JSON.parse(localStorage.getItem('mu')||'{"xp":0,"streak":0,"lastDay":null,"ach":[]}')
};
const save=()=>{localStorage.setItem('mp',JSON.stringify(S.progress));localStorage.setItem('mu',JSON.stringify(S.user));};

// ============ Toasts & Sound ============
const audioCtx=new(window.AudioContext||window.webkitAudioContext)();
function beep(f=440,d=.1,v=.1,t='sine'){
  try{const o=audioCtx.createOscillator(),g=audioCtx.createGain();
  o.connect(g);g.connect(audioCtx.destination);o.frequency.value=f;
  o.type=t;g.gain.setValueAtTime(v,audioCtx.currentTime);
  g.gain.exponentialRampToValueAtTime(.001,audioCtx.currentTime+d);
  o.start();o.stop(audioCtx.currentTime+d);}catch(e){}
}
const sound={correct:()=>{beep(523,.1);setTimeout(()=>beep(784,.15),80);},wrong:()=>beep(200,.2,.15,'sawtooth'),click:()=>beep(800,.05,.05),finish:()=>{beep(523,.1);setTimeout(()=>beep(659,.1),120);setTimeout(()=>beep(784,.2),240);},unlock:()=>{beep(659,.1);setTimeout(()=>beep(880,.15),100);setTimeout(()=>beep(1047,.2),200);}};
function toast(msg,type=''){const t=document.getElementById('toast');t.textContent=msg;t.className='toast show '+type;setTimeout(()=>t.className='toast',2400);}

// ============ Theme ============
document.getElementById('themeToggle').addEventListener('click',()=>{
  const h=document.documentElement;const n=h.dataset.theme==='dark'?'light':'dark';
  h.dataset.theme=n;document.getElementById('themeIcon').textContent=n==='dark'?'🌙':'☀️';
  localStorage.setItem('theme',n);
});
if(localStorage.getItem('theme')){document.documentElement.dataset.theme=localStorage.getItem('theme');document.getElementById('themeIcon').textContent=localStorage.getItem('theme')==='dark'?'🌙':'☀️';}

// ============ Navigation ============
function go(id){
  if(S.exam.int&&id!=='examScreen'){clearInterval(S.exam.int);S.exam.int=null;}
  document.querySelectorAll('.screen').forEach(s=>s.classList.remove('active'));
  document.getElementById(id).classList.add('active');
  window.scrollTo({top:0,behavior:'smooth'});
}
document.querySelectorAll('[data-go]').forEach(el=>el.addEventListener('click',()=>{sound.click();go(el.dataset.go);}));

// ============ Streak ============
function updateStreak(){
  const today=new Date().toDateString();
  if(S.user.lastDay!==today){
    const y=new Date();y.setDate(y.getDate()-1);
    if(S.user.lastDay===y.toDateString())S.user.streak++;
    else if(S.user.lastDay!==null)S.user.streak=1;
    else S.user.streak=1;
    S.user.lastDay=today;save();
  }
}

// ============ Achievements ============
const ACHS=[
  {id:'first',name:'البداية',desc:'أول درس',icon:'🎯',check:()=>Object.keys(S.progress).length>=1},
  {id:'three',name:'متعلم نشيط',desc:'3 دروس',icon:'📚',check:()=>Object.keys(S.progress).length>=3},
  {id:'all',name:'خبير',desc:'كل الدروس',icon:'🏆',check:()=>Object.keys(S.progress).length>=6},
  {id:'high',name:'ممتاز',desc:'نتيجة 100%',icon:'💯',check:()=>Object.values(S.progress).some(p=>p.best===100)},
  {id:'good',name:'جيد جداً',desc:'نتيجة 90%+',icon:'⭐',check:()=>Object.values(S.progress).some(p=>p.best>=90)},
  {id:'streak3',name:'منتظم',desc:'سلسلة 3 أيام',icon:'🔥',check:()=>S.user.streak>=3},
];
function checkAchievements(){
  const newAch=[];
  ACHS.forEach(a=>{if(!S.user.ach.includes(a.id)&&a.check()){S.user.ach.push(a.id);newAch.push(a);}});
  if(newAch.length){save();sound.unlock();showAchPop(newAch);}
}
function showAchPop(achs){
  const pop=document.getElementById('newAchievement');
  if(achs.length){pop.style.display='inline-flex';document.getElementById('newAchText').textContent='إنجاز جديد: '+achs[0].name+' '+achs[0].icon;}
}
function renderAch(){
  const grid=document.getElementById('achGrid');
  grid.innerHTML=ACHS.map(a=>{
    const u=S.user.ach.includes(a.id);
    return `<div class="ach ${u?'unlocked':'locked'}">
      <div class="ach-icon">${a.icon}</div>
      <div class="ach-name">${a.name}</div>
      <div class="ach-desc">${a.desc}</div>
    </div>`;
  }).join('');
}

// ============ Stats ============
function updateStats(){
  updateStreak();
  const done=Object.keys(S.progress).length;
  const exams=Object.values(S.progress).filter(p=>p.best!==undefined).length;
  const avg=exams?Math.round(Object.values(S.progress).reduce((a,p)=>a+(p.best||0),0)/exams):0;
  document.getElementById('completedCount').textContent=done;
  document.getElementById('avgScore').textContent=avg+'%';
  document.getElementById('totalExams').textContent=exams;
  document.getElementById('streakCount').textContent=S.user.streak;
  document.getElementById('homeStreak').textContent=S.user.streak;
  document.getElementById('xpCount').textContent=S.user.xp;
}

// ============ Lessons Grid ============
function renderLessons(filter='الكل'){
  let ls=LESSONS;
  if(filter!=='all'&&filter!=='الكل')ls=ls.filter(l=>l.difficulty===filter);
  const grid=document.getElementById('lessonsGrid');
  grid.innerHTML=ls.map(l=>{
    const d=S.progress[l.id];
    return `<div class="mod-card" data-id="${l.id}">
      <div class="lesson-tile">
        ${d?`<div class="badge-top">✓ ${d.best||0}%</div>`:''}
        <div class="lesson-icon" style="background:${l.color}22;color:${l.color};">${l.icon}</div>
        <h3>${l.title}</h3>
        <p>${l.description}</p>
        <span class="diff diff-${l.difficulty}">${l.difficulty}</span>
        <div class="arrow">←</div>
      </div>
    </div>`;
  }).join('');
  grid.querySelectorAll('.mod-card').forEach(c=>c.addEventListener('click',()=>{sound.click();openLesson(c.dataset.id);}));
}

document.querySelectorAll('.filter-chip').forEach(b=>b.addEventListener('click',()=>{
  document.querySelectorAll('.filter-chip').forEach(x=>x.classList.remove('active'));
  b.classList.add('active');sound.click();renderLessons(b.dataset.filter);
}));

// ============ Lesson Page ============
function openLesson(id){
  const l=LESSONS.find(x=>x.id===id);S.currentLesson=l;
  document.getElementById('lessonTitle').textContent=l.title;
  document.getElementById('lessonContent').innerHTML=l.content;
  const m=document.getElementById('markDone');
  m.textContent=S.progress[id]?'✓':'✓';m.style.color=S.progress[id]?'var(--suc)':'';
  m.onclick=()=>{if(!S.progress[id]){S.progress[id]={best:0,completed:true};save();updateStats();toast('تم标记 الدرس كمكتمل ✓');}else toast('الدرس مكتمل مسبقاً','warn');};
  go('lessonScreen');
}

// ============ Start Exam ============
function startExam(){
  const l=S.currentLesson;
  const qs=[...l.exam].sort(()=>Math.random()-.5).slice(0,Math.min(6,l.exam.length));
  S.exam={questions:qs,answers:new Array(qs.length).fill(null),idx:0,timer:0,
    int:setInterval(()=>{S.exam.timer++;const m=String(Math.floor(S.exam.timer/60)).padStart(2,'0');const s=String(S.exam.timer%60).padStart(2,'0');document.getElementById('timer').textContent=`${m}:${s}`;},1000)};
  go('examScreen');renderQ();
}

// ============ Render Question ============
function renderQ(){
  const {questions,idx,answers}=S.exam;
  const q=questions[idx];const total=questions.length;
  document.getElementById('questionCounter').textContent=`سؤال ${idx+1} من ${total}`;
  document.getElementById('progressFill').style.width=`${((idx+1)/total)*100}%`;
  document.getElementById('btnPrev').disabled=idx===0;
  document.getElementById('btnNext').textContent=idx===total-1?'إنهاء ✓':'التالي →';
  const letters=['أ','ب','ج','د','هـ'];
  let h=`<span class="q-num">سؤال ${idx+1}</span><div class="q-text">${q.q}</div><div class="opts">`;
  if(q.type==='mcq'){
    q.options.forEach((o,i)=>{
      if(answers[idx]!==null){
        if(i===q.answer)h+=`<div class="opt correct"><span class="opt-letter">✓</span><span>${o}</span></div>`;
        else if(i===answers[idx])h+=`<div class="opt wrong"><span class="opt-letter">✗</span><span>${o}</span></div>`;
        else h+=`<div class="opt" style="opacity:.5"><span class="opt-letter">${letters[i]}</span><span>${o}</span></div>`;
      }else h+=`<div class="opt" data-o="${i}"><span class="opt-letter">${letters[i]}</span><span>${o}</span></div>`;
    });
  }else{
    const chk=answers[idx]!==null;
    [['صحيح',true],['خطأ',false]].forEach(([lbl,v])=>{
      if(chk){
        if(v===q.answer)h+=`<div class="opt correct"><span class="opt-letter">✓</span><span>${lbl}</span></div>`;
        else if(v===answers[idx])h+=`<div class="opt wrong"><span class="opt-letter">✗</span><span>${lbl}</span></div>`;
        else h+=`<div class="opt" style="opacity:.5"><span class="opt-letter">•</span><span>${lbl}</span></div>`;
      }else h+=`<div class="opt" data-tf="${v}"><span class="opt-letter">${lbl.charAt(0)}</span><span>${lbl}</span></div>`;
    });
  }
  h+='</div>';document.getElementById('questionCard').innerHTML=h;
  if(answers[idx]===null){
    document.querySelectorAll('[data-o]').forEach(el=>el.addEventListener('click',()=>{S.exam.answers[idx]=parseInt(el.dataset.o);sound.click();renderQ();}));
    document.querySelectorAll('[data-tf]').forEach(el=>el.addEventListener('click',()=>{S.exam.answers[idx]=el.dataset.tf==='true';const ok=S.exam.answers[idx]===q.answer;ok?(sound.correct()):sound.wrong();renderQ();}));
  }else{
    const ok=answers[idx]===q.answer;if(ok)sound.correct();else sound.wrong();
  }
}

document.getElementById('btnPrev').addEventListener('click',()=>{if(S.exam.idx>0){S.exam.idx--;renderQ();}});
document.getElementById('btnNext').addEventListener('click',()=>{
  const{idx,answers,questions}=S.exam;
  if(answers[idx]===null){toast('اختر إجابة أولاً','warn');return;}
  if(idx<questions.length-1){S.exam.idx++;renderQ();}else finishExam();
});

// ============ Finish Exam ============
function finishExam(){
  clearInterval(S.exam.int);
  const{questions,answers,timer}=S.exam;
  let correct=0;questions.forEach((q,i)=>{if(answers[i]===q.answer)correct++;});
  const pct=Math.round((correct/questions.length)*100);
  const xp=correct*10+(pct===100?50:pct>=80?25:pct>=50?10:0);
  S.user.xp+=xp;save();
  const lid=S.currentLesson.id;
  if(!S.progress[lid])S.progress[lid]={};
  S.progress[lid].best=Math.max(pct,S.progress[lid].best||0);
  S.progress[lid].last=pct;S.progress[lid].completed=true;
  save();updateStats();
  // Result UI
  let icon='🎉',title='ممتاز!',msg='أداء رائع، أنت فاهم المادة.';
  if(pct<80){icon='👍';title='جيد، استمر!';msg='مستوى جيد لكن في مجال للتحسن.';}
  if(pct<50){icon='💪';title='تحتاج مراجعة';msg='أعد قراءة الدرس والمحاولة مرة أخرى.';}
  document.getElementById('resultIcon').textContent=icon;
  document.getElementById('resultTitle').textContent=title;
  document.getElementById('resultMsg').textContent=msg;
  document.getElementById('scoreNum').textContent=pct;
  document.getElementById('correctNum').textContent=correct;
  document.getElementById('totalNum').textContent=questions.length;
  document.getElementById('earnedXp').textContent='+'+xp;
  const mm=String(Math.floor(timer/60)).padStart(2,'0');const ss=String(timer%60).padStart(2,'0');
  document.getElementById('timeSpent').textContent=`${mm}:${ss}`;
  // Ring
  setTimeout(()=>{
    const off=326.7-(pct/100)*326.7;
    const c=document.getElementById('scoreCircle');c.style.strokeDashoffset=off;
  },100);
  // Confetti & sound
  if(pct>=50){sound.finish();if(pct===100)confetti();else if(pct>=80)lightConfetti();}
  document.getElementById('newAchievement').style.display='none';
  checkAchievements();
  go('resultScreen');
}

function confetti(){const c=document.getElementById('confetti');c.innerHTML='';const cols=['#7c3aed','#06b6d4','#f59e0b','#10b981','#ec4899','#ef4444'];
  for(let i=0;i<60;i++){const el=document.createElement('i');el.style.left=Math.random()*100+'%';el.style.background=cols[Math.floor(Math.random()*cols.length)];el.style.animationDelay=Math.random()*2+'s';el.style.animationDuration=(2+Math.random()*2)+'s';c.appendChild(el);}}
function lightConfetti(){const c=document.getElementById('confetti');c.innerHTML='';const cols=['#7c3aed','#06b6d4','#f59e0b'];
  for(let i=0;i<25;i++){const el=document.createElement('i');el.style.left=Math.random()*100+'%';el.style.background=cols[Math.floor(Math.random()*cols.length)];el.style.animationDelay=Math.random()*1+'s';el.style.animationDuration=(2+Math.random()*2)+'s';c.appendChild(el);}}

// ============ Review ============
function showReview(){
  const{questions,answers}=S.exam;
  document.getElementById('reviewContent').innerHTML=questions.map((q,i)=>{
    const ok=answers[i]===q.answer;
    let ua,ca;
    if(q.type==='mcq'){ua=answers[i]!==null?q.options[answers[i]]:'لم يُجب';ca=q.options[q.answer];}
    else{ua=answers[i]!==null?(answers[i]?'صحيح':'خطأ'):'لم يُجب';ca=q.answer?'صحيح':'خطأ';}
    return `<div class="review-item ${ok?'r':'w'}">
      <h3>${i+1}. ${q.q}</h3>
      <div class="ya ${ok?'ya-r':'ya-w'}"><strong>إجابتك:</strong> ${ua} ${ok?'✅':'❌'}</div>
      ${!ok?`<div class="ya ya-r"><strong>الصحيحة:</strong> ${ca}</div>`:''}
      <div class="explain">💡 ${q.exp}</div>
    </div>`;
  }).join('');
  go('reviewScreen');
}
document.getElementById('btnReview').addEventListener('click',showReview);
document.getElementById('backToResult').addEventListener('click',()=>go('resultScreen'));
document.getElementById('btnRetake').addEventListener('click',startExam);
document.getElementById('startBtn').addEventListener('click',()=>{renderLessons();go('lessonsScreen');});
document.getElementById('btnReRead').addEventListener('click',()=>window.scrollTo({top:0,behavior:'smooth'}));
document.getElementById('btnStartExam').addEventListener('click',startExam);

