// ============ بدء الامتحان ============
function startExam(){
  if(!S.questions.length){
    toast('لا توجد أسئلة، أعد الشرح','warn');
    return;
  }
  S.exam = {
    idx:0,
    answers: new Array(S.questions.length).fill(null),
    timer:0,
    int: setInterval(()=>{
      S.exam.timer++;
      const m = String(Math.floor(S.exam.timer/60)).padStart(2,'0');
      const s = String(S.exam.timer%60).padStart(2,'0');
      $('timer').textContent = m+':'+s;
    },1000)
  };
  go('examScreen');
  renderQuestion();
}

function renderQuestion(){
  const q = S.questions[S.exam.idx];
  const total = S.questions.length;
  const typeMap = {'mcq':'خيارات', 'fill':'املأ الفراغ', 'tf':'صح أو خطأ', 'essay':'مقالي'};
  const typeLabel = typeMap[q.type] || '';

  $('questionCounter').textContent = 'سؤال '+(S.exam.idx+1)+' من '+total;
  $('progressFill').style.width = ((S.exam.idx+1)/total*100)+'%';
  $('btnPrev').disabled = S.exam.idx === 0;
  $('btnNext').textContent = S.exam.idx === total-1 ? 'إنهاء ✓' : 'التالي →';

  let html = '<span class="q-num">سؤال '+(S.exam.idx+1)+'</span> <span class="q-type">📚 '+typeLabel+'</span>';
  html += '<div class="q-text">'+q.q+'</div>';

  const answered = S.exam.answers[S.exam.idx] !== null;

  if(q.type === 'mcq'){
    html += '<div class="opts">';
    const letters = ['أ','ب','ج','د'];
    q.opts.forEach((o,i)=>{
      let cls = 'opt';
      if(answered){
        if(i === q.idx) cls += ' correct';
        else if(String(i) === S.exam.answers[S.exam.idx]) cls += ' wrong';
        else cls += '';
      }
      html += '<div class="'+cls+'" '+(!answered?'data-o="'+i+'" ':'')+'>';
      html += '<span class="opt-letter">'+(answered && i===q.idx?'✓':answered && String(i)===S.exam.answers[S.exam.idx]?'✗':letters[i])+'</span>';
      html += '<span>'+o+'</span></div>';
    });
    html += '</div>';
  } else if(q.type === 'fill'){
    if(answered){
      const ok = String(S.exam.answers[S.exam.idx]).trim() === q.ans.trim();
      html += '<input class="essay-input" value="'+S.exam.answers[S.exam.idx]+'" disabled style="border-color:'+(ok?'var(--suc)':'var(--dan)')+'">';
      if(!ok) html += '<div style="color:var(--suc);margin-top:8px">الإجابة الصحيحة: <strong>'+q.ans+'</strong></div>';
    }else{
      html += '<input class="essay-input" id="fillInput" placeholder="اكتب الكلمة التي تملأ الفراغ...">';
    }
  } else if(q.type === 'tf'){
    html += '<div class="opts">';
    if(answered){
      const user = S.exam.answers[S.exam.idx] === 'true';
      const cor = q.ans;
      html += '<div class="opt '+(cor?'correct':'')+'"><span class="opt-letter">'+(cor?'✓':'✗')+'</span><span>صحيح</span></div>';
      html += '<div class="opt '+(user===cor?'':'wrong')+'"><span class="opt-letter">'+(user===cor?'✓':'✗')+'</span><span>خطأ</span></div>';
    } else {
      html += '<div class="opt" data-tf="true"><span class="opt-letter">ص</span><span>صحيح</span></div>';
      html += '<div class="opt" data-tf="false"><span class="opt-letter">خ</span><span>خطأ</span></div>';
    }
    html += '</div>';
  } else if(q.type === 'essay'){
    html += '<textarea class="essay-input" id="essayInput" placeholder="اشرح بكلماتك الخاصة..." '+ (answered?'disabled':'')+'>'+ (answered||'')+'</textarea>';
  }

  $('questionCard').innerHTML = html;

  if(!answered){
    if(q.type === 'mcq'){
      document.querySelectorAll('[data-o]').forEach(el=>{
        el.addEventListener('click',()=>{
          S.exam.answers[S.exam.idx] = el.dataset.o;
          renderQuestion();
        });
      });
    } else if(q.type === 'tf'){
      document.querySelectorAll('[data-tf]').forEach(el=>{
        el.addEventListener('click',()=>{
          S.exam.answers[S.exam.idx] = el.dataset.tf;
          renderQuestion();
        });
      });
    } else if(q.type === 'fill'){
      const inp = $('fillInput');
      if(inp){
        inp.addEventListener('keydown',e=>{
          if(e.key==='Enter'){
            S.exam.answers[S.exam.idx] = inp.value;
            renderQuestion();
          }
        });
        inp.focus();
      }
    } else if(q.type === 'essay'){
      const inp = $('essayInput');
      if(inp){
        inp.focus();
      }
    }
  }
}

$('btnPrev').addEventListener('click',()=>{
  saveEssayText();
  if(S.exam.idx>0){S.exam.idx--;renderQuestion();}
});
$('btnNext').addEventListener('click',()=>{
  saveEssayText();
  const q = S.questions[S.exam.idx];
  const ans = S.exam.answers[S.exam.idx];
  if(ans === null && q.type !== 'essay'){
    toast('اختر إجابة أولاً','warn');
    return;
  }
  if(q.type === 'essay' && (!ans || ans.trim().length < 5)){
    if(!confirm('إجابتك قصيرة جداً. متابعة؟')) return;
  }
  if(S.exam.idx < S.questions.length-1){
    S.exam.idx++;renderQuestion();
  } else {
    finishExam();
  }
});

function saveEssayText(){
  const q = S.questions[S.exam.idx];
  const inp = $('essayInput');
  if(q && q.type==='essay' && inp && inp.value){
    S.exam.answers[S.exam.idx] = inp.value;
  }
}

// ============ إنهاء الامتحان وتقييم المقالي ============
function evaluateEssay(userAns, ref){
  if(!userAns || !ref) return 0;
  const u = userAns.toLowerCase();
  const r = ref.toLowerCase();
  const rWords = r.split(/\s+/).filter(w=>w.length>=3);
  let hits = 0;
  rWords.forEach(w => { if(u.includes(w.toLowerCase())) hits++; });
  const ratio = hits / Math.max(rWords.length,1);
  // مع scoring: 50% + نسبة hit
  if(u.includes(r)) return 100;
  if(ratio >= 0.5) return 75;
  if(ratio >= 0.25) return 50;
  if(ratio > 0 || userAns.length > 20) return 25;
  return 0;
}

function finishExam(){
  clearInterval(S.exam.int);
  saveEssayText();
  const {questions, answers, timer} = S.exam;
  let correct = 0;
  questions.forEach((q,i)=>{
    const a = answers[i];
    if(a === null || a === undefined) return;
    if(q.type === 'mcq'){
      if(String(a) === String(q.idx)) correct++;
    } else if(q.type === 'tf'){
      if(String(a) === String(q.ans)) correct++;
    } else if(q.type === 'fill'){
      if(String(a).trim() === String(q.ans).trim()) correct++;
    } else if(q.type === 'essay'){
      const score = evaluateEssay(a, q.ref);
      if(score >= 75) correct++;
      else if(score >= 50) correct += 0.5;
    }
  });
  const pct = Math.round((correct/questions.length)*100);

  let icon='🎉',title='ممتاز!',msg='إجابات رائعة - أنت فاهم المادة فعلياً.';
  if(pct<80){icon='👍';title='جيد';msg='فهمك متوسط - حاول تعيد النظر.';}
  if(pct<50){icon='💪';title='يحتاج مراجعة';msg='استمع لشرحك وأعد المحاولة.';}
  $('resultIcon').textContent = icon;
  $('resultTitle').textContent = title;
  $('resultMsg').textContent = msg;
  $('scoreNum').textContent = pct;
  $('correctNum').textContent = Math.round(correct);
  $('totalNum').textContent = questions.length;
  const mm=String(Math.floor(timer/60)).padStart(2,'0');
  const ss=String(timer%60).padStart(2,'0');
  $('timeSpent').textContent = mm+':'+ss;
  setTimeout(()=>{
    $('scoreCircle').style.strokeDashoffset = 326.7 - (pct/100)*326.7;
  },100);
  if(pct >= 60){
    const c = $('confetti');
    c.innerHTML = '';
    const cols = ['#7c3aed','#06b6d4','#f59e0b','#10b981','#ec4899'];
    for(let i=0;i< (pct===100?80:30); i++){
      const el = document.createElement('i');
      el.style.left = Math.random()*100+'%';
      el.style.background = cols[Math.floor(Math.random()*cols.length)];
      el.style.animationDelay = Math.random()*2+'s';
      el.style.animationDuration = (2+Math.random()*2)+'s';
      c.appendChild(el);
    }
  }
  go('resultScreen');
}

// ============ المراجعة ============
function showReview(){
  const {questions, answers} = S.exam;
  $('reviewContent').innerHTML = questions.map((q,i)=>{
    let ok = false;
    let ua = '', ca = '';
    if(q.type === 'mcq'){
      ua = answers[i] !== null ? q.opts[answers[i]] : 'لم تُجب';
      ca = q.opts[q.idx];
      ok = String(answers[i]) === String(q.idx);
    } else if(q.type === 'tf'){
      ua = answers[i] !== null ? (answers[i]==='true'?'صحيح':'خطأ') : 'لم تُجب';
      ca = q.ans ? 'صحيح' : 'خطأ';
      ok = String(answers[i]) === String(q.ans);
    } else if(q.type === 'fill'){
      ua = answers[i] || 'لم تُجب';
      ca = q.ans;
      ok = String(answers[i]).trim() === String(q.ans).trim();
    } else if(q.type === 'essay'){
      ua = answers[i] || 'لم تُجب';
      ca = q.refSent;
      const s = evaluateEssay(answers[i]||'', q.ref);
      ok = s >= 75;
    }
    return '<div class="review-item '+(ok?'r':'w')+'">'+
      '<h3>'+(i+1)+'. '+q.q+'</h3>'+
      '<div class="ya '+(ok?'r':'w')+'"><strong>إجابتك:</strong> '+ua+' '+(ok?'✅':'❌')+'</div>'+
      (!ok?'<div class="ya r"><strong>المتوقع:</strong> '+ca+'</div>':'')+
      '<div class="explain">💡 '+q.exp+'</div>'+
    '</div>';
  }).join('');
  go('reviewScreen');
}

$('btnReview').addEventListener('click', showReview);
$('backToResult').addEventListener('click',()=>go('resultScreen'));
$('btnRetake').addEventListener('click', startExam);

